// CHECKS registry — add new capabilities here only, never touch the guard logic below
const CHECKS = {
  telegram: {
    env: ['TELEGRAM_BOT_TOKEN', 'APPROVAL_CHAT_ID'],
    instructions: 'Set TELEGRAM_BOT_TOKEN and APPROVAL_CHAT_ID in /opt/n8n.env (or Infisical), then restart n8n. Ensure the Telegram Bot credential is configured in n8n Settings > Credentials.',
    onboarding_workflow: '[YAOC2] Onboarding — Capability: Telegram'
  },
  whatsapp: {
    env: ['EVOLUTION_API_URL', 'EVOLUTION_API_KEY', 'EVOLUTION_INSTANCE_NAME', 'WHATSAPP_PHONE'],
    instructions: 'Set EVOLUTION_API_URL, EVOLUTION_API_KEY, EVOLUTION_INSTANCE_NAME, and WHATSAPP_PHONE in /opt/n8n.env. Ensure Evolution API is running and the instance is connected.',
    onboarding_workflow: '[YAOC2] Onboarding — Capability: WhatsApp'
  },
  deepseek: {
    env: ['DEEPSEEK_API_KEY'],
    instructions: 'Set DEEPSEEK_API_KEY in /opt/n8n.env or Infisical. DeepSeek uses an OpenAI-compatible endpoint at https://api.deepseek.com/v1 — no separate base URL needed.',
    onboarding_workflow: '[YAOC2] Onboarding — Capability: LLM Provider'
  },
  slack: {
    env: ['SLACK_BOT_TOKEN', 'SLACK_SIGNING_SECRET', 'SLACK_DEFAULT_CHANNEL'],
    instructions: 'Create a Slack app at api.slack.com/apps, add Bot Token Scopes (chat:write, channels:read, channels:history), install to workspace. Set SLACK_BOT_TOKEN (xoxb-...), SLACK_SIGNING_SECRET, and SLACK_DEFAULT_CHANNEL (#channel-name) in /opt/n8n.env.',
    onboarding_workflow: '[YAOC2] Onboarding — Capability: Slack'
  },
  'openai-compat': {
    env: ['OPENAI_COMPAT_BASE_URL', 'OPENAI_COMPAT_KEY'],
    instructions: 'Set OPENAI_COMPAT_BASE_URL (e.g. https://api.openai.com/v1 or your local Ollama/LM Studio URL) and OPENAI_COMPAT_KEY in /opt/n8n.env. Most providers (OpenAI, Groq, Mistral, local models) use this pattern.',
    onboarding_workflow: '[YAOC2] Onboarding — Capability: LLM Provider'
  }
};

const capability = ($input.item.json.capability ?? '').toLowerCase().trim();

if (!capability) {
  return [{ json: {
    status: 'missing',
    missingFields: ['capability'],
    instructions: 'Pass a capability string as input. Valid values: ' + Object.keys(CHECKS).join(', '),
    onboarding_workflow: null
  } }];
}

const check = CHECKS[capability];
if (!check) {
  return [{ json: {
    status: 'missing',
    missingFields: ['capability'],
    instructions: `Unknown capability '${capability}'. Valid values: ${Object.keys(CHECKS).join(', ')}.`,
    onboarding_workflow: null
  } }];
}

const missingFields = check.env.filter(envVar => {
  const val = $env[envVar];
  return !val || val.trim() === '';
});

if (missingFields.length > 0) {
  return [{ json: {
    status: 'missing',
    capability,
    missingFields,
    instructions: check.instructions,
    onboarding_workflow: check.onboarding_workflow
  } }];
}

return [{ json: { status: 'ok', capability, checkedFields: check.env } }];
